INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-6f0ba476-moex-00444', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '假設你有一位朋友，他不被上司理解，不受同事接納，而你想要寫一段文字鼓勵他堅定地走 自己的路，不被他人影響，追尋自我價值。下列選項，最適當的是：', '["將自己與對方的看法聯結起來，一定要贏過對方才行", "過度誇耀自己的優點，是擔心身邊沒有人會認同自己", "無法接納自我的人容易將他人設為假想敵，用貶抑他人來獲得自信", "真正的自由是不在意他人的評價，不怕被人討厭，貫徹自己的想法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00445', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '下列文句「」中的成語，何者使用最恰當？', '["老師工作時應該「聲色俱厲」，為學生夙夜匪懈", "感謝您大駕光臨，令寒舍「深居簡出」，小弟深感榮幸", "想當年這裡一片荒蕪，全賴前輩們「篳路藍縷」，才能欣欣向榮", "公司高層每日「披肝瀝膽」，你初來乍到要多加提防，免遭陷害"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00446', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '下列文句「」中的成語，何者使用正確？', '["他最近正在減重，本著「虛懷若谷」的意志力，吃得很節制", "當鳳凰花開季節，就是同學們要互道珍重、「分庭抗禮」的時候", "公司財務面臨危機，幸好老闆決定轉賣閒置廠房，堪稱「見異思遷」", "人應該要學習負責，這位母親「李代桃僵」，為女兒頂罪，反而害了她"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00447', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '下列文句「」內的詞語，用法錯誤的選項是：', '["他「逢人說項」，到處吹噓自己的勇猛", "他向來循規蹈矩，不會做出「雞鳴狗盜」的勾當", "經過此番激烈的砲戰，從此敵人不敢再「越雷池一步」", "李安拍了很多好片，獲獎無數，是導演行業的「個中翹楚」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00448', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '下列文句「」中的成語，何者使用錯誤？', '["警方接到報案趕到現場，匪徒早已「杳如黃鶴」，不見蹤影", "這項工程最終靠著大家「任勞任怨」、努力不懈，才得以完成", "王教授的演講十分精彩，全場人士聽得「津津有味」，讚嘆不已", "我們公司非常嚴格，對任何流程的監控都小心翼翼，「瑕不掩瑜」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00449', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '下列選項，何者最適宜「醫界」使用？', '["功著杏林", "利惠人群", "大業千秋", "福國利民"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00450', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '下列選項中的題辭與使用場合搭配，何者正確？', '["畢業：學無止境", "女喪：孟母遺風", "退休：德業長昭", "遷居：名山事業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00451', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '下列文句「」中的成語，何者使用正確？', '["人事變化無常，不禁令人生起「樹猶如此」的慨嘆", "時逢春季，陽明山處處「蕙質蘭心」，吸引民眾駐足", "彎月高懸天際，「送眼流眉」的姿態，美得令人屏息", "跨年人潮眾多，一時之間「擢髮難數」，捷運只好加開班次"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00452', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「後人認為司馬遷在《史記》裡對現實政治『微文刺譏』，因而視《史記》為『謗書』。當 然，司馬遷在寫作過程中，將其個人際遇的鬱結，融於書中，是非常可能的。至於『微文刺 譏』，誹謗今上，在現實的政治環境下，卻是不可能的。身受現實政治摧殘的司馬遷，如何 超越桎梏，在不觸犯時諱的情況下，記錄當代歷史，頗費思量。」 根據上文，下列選項何者最符合文意？', '["司馬遷受現實政治摧殘，因而在《史記》誹謗今上", "《史記》「微文刺譏」展現歷史學家的真誠與勇氣", "如何寄託個人的鬱結，是司馬遷撰作《史記》時最費思量者", "能忠實呈現當代歷史而不觸犯時諱，是《史記》寫作的難處"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00453', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「根據影片中象龜熟練的獵捕技巧，生態學家Justin Gerlach 推測或許這些象龜其實早已學 會捕獵，但因為過去人類侵入牠們的棲息地，大量獵捕各種生物，而大大影響原棲息地的食 物鏈，才導致象龜改變原本的習性。或許也是弗雷格特島所提倡的保育計畫實行得很成功， 使象龜們回歸了原始的生長環境，因此象龜們的狩獵本性就露出來了。」 根據上文，下列選項何者符合文意？', '["過去人們普遍認為象龜不會獵捕", "象龜獵捕行為是被人類所逼迫的", "象龜改變原本的習性後開始吃肉", "只有弗雷格特島的象龜才會獵捕"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
